f9c35101-3972-4e9a-b083-db8bf6c565fb	/	POP INTERFIT BAC	[{"id": "4c507997-4663-4271-9e20-2ae45cbc6641", "type": "heading", "content": "POP INTERFIT BAC"}, {"id": "3489d733-1de7-4504-a091-b68ab06eb221", "type": "text", "content": "Procedimentos Operacionais Padrão"}, {"id": "17675b6c-4238-421a-84db-0a99b9e56a77", "type": "text", "content": "Essa é a central oficial dos procedimentos que guiam o dia a dia da Interfit. Aqui você encontra orientações claras para garantir padrão, qualidade e consistência em todas as ações da equipe."}, {"id": "b2464785-aa89-4ec1-9fe5-391fd7cef66c", "type": "heading2", "content": "Equipe"}, {"id": "efa1abd6-01ac-4cce-80da-42cfff141842", "type": "list", "content": "- Abertura e fechamento\\n- Consultores de relacionamento\\n- Limpeza\\n- Manutenção"}, {"id": "61bdd80c-092c-47e1-a8a5-7cd7311c850c", "type": "heading2", "content": "Políticas"}, {"id": "11d6e97d-6db2-4305-98c4-a8876a481190", "type": "list", "content": "- Conceito Interfit\\n- Regimento interno\\n- Missão, visão e valores"}, {"id": "4be12e11-b503-4f45-bf13-9f7ffda2e608", "type": "heading2", "content": "Rotinas"}, {"id": "74269943-22ca-4af2-bf66-80c55478de66", "type": "list", "content": "- Diário\\n- Semanal\\n- Quinzenal\\n- Mensal"}]	1521afca-4e5c-4e9e-aa59-8e70ce2c6ce6	2026-04-12 18:55:15.544706+00	2026-04-12 19:07:52.588192+00
