71442ba8-3a58-44d8-8fe1-190e6ef1cc6a	/equipe/abertura-fechamento/abertura	IFAC - Checklist de Abertura	[{"id": "5ec6b45c-2f3b-47c6-bd06-e328dd6b38b6", "type": "heading", "content": "🌅 IFAC - Checklist de Aberturas"}, {"id": "a30786ea-854d-494a-9adb-8521bc594660", "type": "image", "content": ""}, {"id": "e81a29b3-b7a4-438d-91fc-eb9178610ac5", "type": "text", "content": "Procedimentos obrigatórios para abertura da unidade. Siga todos os itens do checklist abaixo para garantir que a academia esteja pronta para receber os alunos."}, {"id": "05571fc1-9f67-4f68-b4e2-5e31c68db255", "type": "heading2", "content": "⏰ Importante"}, {"id": "ba4c186b-9d36-421a-993c-326a651ff2aa", "type": "text", "content": ""}, {"id": "ef234294-d77b-4f30-af96-eecf7cd73d02", "type": "text", "content": "O responsável pela abertura deve chegar pelo menos 15 minutos antes do horário oficial de funcionamento.\\n"}, {"id": "bea0cde4-0596-45a8-83f4-8157f8e0ac91", "type": "image", "content": ""}, {"id": "fae86e23-6a9a-487c-a499-ba9c8141d0c7", "type": "heading2", "content": "Procedimentos de Abertura"}, {"id": "8cfc3788-90fb-46d6-81a2-156060fd9d72", "type": "checklist", "content": [{"id": "1", "label": "Chegar 15 minutos antes do horário de abertura", "checked": false}, {"id": "2", "label": "Desligar o alarme e abrir as portas de acesso", "checked": false}, {"id": "3", "label": "Ligar as luzes de todas as áreas (musculação, cardio, recepção, vestiários)", "checked": false}, {"id": "4", "label": "Ligar o sistema de som e ajustar volume adequado", "checked": false}, {"id": "5", "label": "Ligar ar-condicionado/ventiladores conforme necessidade", "checked": false}, {"id": "6", "label": "Verificar limpeza geral do ambiente (piso, espelhos, equipamentos)", "checked": false}, {"id": "7", "label": "Conferir disponibilidade de toalhas e materiais de higiene nos vestiários", "checked": false}, {"id": "8", "label": "Organizar equipamentos e acessórios (anilhas, halteres, colchonetes)", "checked": false}, {"id": "9", "label": "Ligar e testar o sistema de catraca/controle de acesso", "checked": false}, {"id": "10", "label": "Abrir o sistema de gestão no computador da recepção", "checked": false}, {"id": "11", "label": "Verificar agenda de aulas e profissionais do dia", "checked": false}, {"id": "12", "label": "Checar se há recados ou ocorrências do dia anterior", "checked": false}, {"id": "13", "label": "Conferir estoque de produtos (água, suplementos, se aplicável)", "checked": false}, {"id": "14", "label": "Testar bebedouros e verificar galões de água", "checked": false}, {"id": "15", "label": "Posicionar materiais de divulgação/avisos atualizados", "checked": false}]}, {"id": "dff3ced1-09da-4928-a011-cc483ae7d9f6", "type": "image", "content": ""}, {"id": "bc3ece94-5ce5-4b68-8e92-fb2215bb6e12", "type": "heading", "content": ""}, {"id": "e244093c-5819-4a86-bfce-b245e10a83fa", "type": "image", "content": ""}, {"id": "e8d09d61-b8e5-4c41-a41b-d8ba7191c634", "type": "image", "content": ""}, {"id": "64984a2a-0597-48cb-a858-6ed4c1776a0d", "type": "checklist", "content": []}, {"id": "cb1d3f7b-25e6-4d52-87c2-6c681c30e75f", "type": "flow", "content": {"edges": [], "nodes": []}}]	1521afca-4e5c-4e9e-aa59-8e70ce2c6ce6	2026-04-12 18:26:47.565449+00	2026-04-12 19:56:10.25098+00
a5a81dc3-11b3-4c34-9820-4ade5887afe7	/equipe/consultores/script-vendas	Script de Vendas	[{"id": "38716b0d-a614-4ec7-92d8-e434f928ab64", "type": "heading", "content": "📝 Script de Vendas"}, {"id": "f8e901ff-fd81-491e-a084-5f3a3d1103a9", "type": "text", "content": "Passo a passo para abordagem, apresentação e fechamento. Adapte o tom conforme o perfil do visitante."}, {"id": "9341aeac-f9af-49dd-97d4-337db3ec0e18", "type": "heading2", "content": "🎯 Orientação"}, {"id": "01659be6-1807-48dc-9898-849439cf71cf", "type": "text", "content": "Siga os passos na ordem. Adapte o tom conforme o perfil do visitante, mas nunca pule a etapa de sondagem."}, {"id": "c6949275-3ce7-4361-a84f-6c0affba2d0b", "type": "heading2", "content": "Passo 1: 👋 Recepção e Acolhimento"}, {"id": "c41f6681-6d5b-4116-ad4e-a183a76d0461", "type": "list", "content": "- Cumprimente com entusiasmo e sorriso\\n- \\"Olá! Bem-vindo(a) à Interfit! Meu nome é [seu nome]. Posso te ajudar?\\"\\n- Ofereça água ou café\\n- Pergunte o nome do visitante e use durante toda a conversa"}, {"id": "428e9751-ec8f-45b8-a324-7a95ef2862b9", "type": "heading2", "content": "Passo 2: 🔍 Sondagem (Entender a Necessidade)"}, {"id": "257ee4d4-71f7-47d7-8728-4815e9ff9725", "type": "list", "content": "- \\"O que te trouxe aqui hoje?\\"\\n- \\"Você já treina ou está começando agora?\\"\\n- \\"Qual seu principal objetivo? (Emagrecimento, hipertrofia, saúde, qualidade de vida)\\"\\n- \\"Tem preferência de horário para treinar?\\"\\n- \\"Já conhece a Interfit ou é sua primeira vez?\\""}, {"id": "40ce1170-f3a0-43fe-925d-c51519454dcd", "type": "heading2", "content": "Passo 3: 🏋️ Tour pela Academia"}, {"id": "8b2b3fd7-6403-44b5-87ca-8229c169ba31", "type": "list", "content": "- Mostre TODAS as áreas: musculação, cardio, funcional, vestiários\\n- Destaque os diferenciais (equipamentos novos, ambiente climatizado, etc.)\\n- Apresente professores que estiverem no momento\\n- Mostre quadro de horários de aulas\\n- Deixe o visitante experimentar um equipamento se possível"}, {"id": "0597045e-fe71-47ee-a1c7-02a0e086bc24", "type": "heading2", "content": "Passo 4: 💰 Apresentação dos Planos"}, {"id": "7691ee92-2ee9-48ec-bcbc-a43c237143f5", "type": "list", "content": "- Apresente do plano mais completo para o mais básico\\n- Destaque o custo-benefício do plano mais adequado ao perfil\\n- \\"Com base no que você me contou, o plano ideal para você seria...\\"\\n- Mostre valores de forma visual (tabela ou material impresso)\\n- Mencione promoções vigentes"}, {"id": "7632b220-7d6f-49bc-b3c2-bd165ce289c5", "type": "heading2", "content": "Passo 5: 🛡️ Contorno de Objeções"}, {"id": "5ebebf58-9006-4911-bcc2-0c2fce781fbc", "type": "list", "content": "- \\"Está caro\\" → \\"Dividindo por dia, fica menos de R$X. É o investimento na sua saúde!\\"\\n- \\"Vou pensar\\" → \\"Entendo! Posso reservar essa condição até amanhã para você?\\"\\n- \\"Preciso falar com alguém\\" → \\"Claro! Posso mandar as informações por WhatsApp?\\"\\n- \\"Não tenho tempo\\" → \\"Temos horários flexíveis. 1 hora, 3x por semana já transforma!\\""}, {"id": "03ed396e-4566-4390-bf5a-af4477315054", "type": "heading2", "content": "Passo 6: ✅ Fechamento"}, {"id": "a085ac0e-0ca0-41e9-b99c-eba52712139c", "type": "list", "content": "- Use fechamento assumido: \\"Vamos começar com o plano X então?\\"\\n- Tenha a ficha de matrícula pronta\\n- Facilite o processo (aceite múltiplas formas de pagamento)\\n- Reforce: \\"Você tomou uma ótima decisão!\\"\\n- Agende a primeira aula/avaliação física"}, {"id": "60c11c78-8364-43be-80b4-5d3d3f23cc3f", "type": "heading2", "content": "Passo 7: 📱 Pós-Venda"}, {"id": "74a9a140-80f7-41bc-95f9-b353c4dbee66", "type": "list", "content": "- Envie mensagem de boas-vindas no WhatsApp\\n- Após 7 dias: pergunte como está a experiência\\n- Após 30 dias: faça check-in sobre resultados\\n- Peça indicações: \\"Tem algum amigo que gostaria de treinar com você?\\""}]	1521afca-4e5c-4e9e-aa59-8e70ce2c6ce6	2026-04-12 19:02:29.805602+00	2026-04-12 19:02:56.779731+00
22bfa989-1489-4d22-82ee-c57d09abf0a2	a1111111-1111-1111-1111-111111111111::pop-processo::402668ae-a1ff-431a-a80b-7a6a6a2cd5a1	Regimento Interno	{"titulo": "Regimento Interno", "conteudo": "<h2>Regimento Interno e Manual de Conduta</h2><p>\\n<strong>Objetivo:</strong> Estabelecer diretrizes de conduta, organização e convivência para garantir um ambiente de trabalho profissional, seguro e alinhado aos valores da Interfit.<br></p>\\n\\n<hr>\\n\\n<h3><p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Introdução <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O presente Regimento Interno tem\\ncomo objetivo estabelecer diretrizes de convivência, conduta e organização do\\ntrabalho entre a empresa e seus colaboradores, promovendo um ambiente\\nprofissional pautado no respeito, na clareza de responsabilidades e na busca\\nconstante pela excelência. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Mais do que um conjunto de\\nregras, este documento representa o compromisso coletivo de todos que fazem\\nparte deste Centro de Treinamento em atuar de forma alinhada com os princípios\\nque orientam a organização. A empresa tem como missão promover saúde, bem-estar\\ne transformação de vida por meio do exercício físico, oferecendo aos alunos um\\natendimento humano, um ambiente seguro e um alto padrão técnico em todas as\\natividades desenvolvidas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Com esse propósito, busca-se\\nconsolidar uma cultura organizacional que permita alcançar a visão de ser\\nreconhecida como referência regional como um CT Premium, destacando-se pela\\nqualidade da experiência oferecida aos alunos, pelos resultados alcançados e\\npela excelência na gestão de pessoas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Para isso, todas as ações e\\ncomportamentos dentro do ambiente de trabalho devem refletir os valores que\\nsustentam a identidade da empresa: respeito, profissionalismo,\\nresponsabilidade, ética, disciplina, trabalho em equipe, foco no aluno,\\nevolução contínua e comprometimento com resultados. Esses princípios orientam\\nas relações internas, a forma de atendimento ao público e a maneira como cada\\ncolaborador desempenha suas funções. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Assim, o Regimento Interno tem a\\nfinalidade de alinhar expectativas, orientar condutas e fortalecer uma cultura\\norganizacional baseada na confiança, na cooperação e na busca permanente por\\nmelhoria e desenvolvimento, contribuindo para que todos trabalhem de forma\\nintegrada em prol da saúde, do bem-estar e da transformação de vida de cada\\naluno atendido. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>A Importância de estabelecer\\ncombinados internos <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Em qualquer ambiente de trabalho,\\nespecialmente em empresas que valorizam o relacionamento humano e a excelência\\nno atendimento, como é o caso da nossa academia, a existência de combinados\\ninternos bem definidos é fundamental para garantir organização, fluidez,\\nrespeito e consistência na conduta de todos os membros da equipe. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Estabelecer combinados internos é\\nmais do que criar regras: é construir acordos conscientes e coletivos sobre\\ncomo devemos agir, interagir e resolver situações cotidianas. Esses combinados\\nfuncionam como um guia seguro para que todos saibam o que se espera de cada um,\\nevitando conflitos, retrabalhos, mal-entendidos e decisões desalinhadas com os\\nvalores da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Ao documentar essas orientações\\npor meio deste Regimento Interno, reforçamos o compromisso da Interfit com uma\\ncultura organizacional clara, ética e respeitosa. Isso fortalece nossa\\nidentidade e garante que o padrão de qualidade no atendimento ao cliente seja\\nmantido, independentemente de quem estiver em serviço. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Cada colaborador,\\nindependentemente de seu tempo de casa ou função exercida, deve estar alinhado\\na esses combinados. Eles foram construídos com base na experiência, nos\\ndesafios enfrentados e no compromisso contínuo com a evolução da academia.&nbsp; Ao cumprir o que foi acordado, demonstramos\\nrespeito uns pelos outros, pelos nossos clientes e pela história que estamos\\nconstruindo juntos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Em resumo, este Regimento não é\\num conjunto de regras imposto de cima para baixo, mas sim um instrumento vivo\\nde governança interna, que traduz a forma como queremos nos relacionar como\\nequipe, servir nossos clientes com excelência e crescer de forma sustentável.\\nSeguir os combinados é um ato de responsabilidade, profissionalismo e lealdade\\ncom tudo o que a Interfit representa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Seja bem-vindo(a) a essa\\njornada.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Bases, Parâmetros e\\nDestinatários <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">E, portanto, a Interfit Academia\\nestabelece suas regras internas de Colaboradores com o objetivo de assegurar um\\nambiente de trabalho harmonioso e eficiente, alinhado ao propósito de\\ncontribuir com Saúde das pessoas garantindo excelência na entrega. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">As Regras da empresa têm como\\nprincipal finalidade conscientizar os Colaboradores sobre seus direitos,\\ndeveres e obrigações, criando métodos, cronogramas e etapas para as principais\\natividades desenvolvidas dentro da Academia, sempre sob a perspectiva de\\nprincípios éticos e morais alicerçado pelos Valores da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O documento vincula-se em todos\\nos seus termos aos contratos e acordos diversos firmados entre a Interfit e\\nseus Colaboradores, incluindo Normas, Circulares, Consolidação das Leis do\\nTrabalho (CLT), Convenção Coletiva do Trabalho (CCT), eventuais Acordos\\nColetivos de Trabalho (ACT), Normas de Saúde e Segurança do trabalho, Lei Geral\\nde Proteção de Dados (LGPD), e normas e determinações governamentais.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Assim como, será base para\\nprocedimentos eventualmente já definidos pela Interfit, tais como, mas não se\\nlimitando, aos procedimentos operacionais padrão e manuais que podem já existir\\nou ser elaborados e desenvolvidos posteriormente pela empresa, sempre dando\\nciência aos Colaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O presente documento é de cunho\\nobrigatório e deve ser seguido por todos os Colaboradores sem exceção. Seu\\ncumprimento é exigido durante todo o período de vigência do contrato de\\ntrabalho, não sendo permitido aos Colaboradores alegarem desconhecimento.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">É importante esclarecer que a\\nadesão aos combinados aqui descritos proporcionará um ambiente de trabalho\\nsaudável e seguro para todos que frequentam a Academia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A inobservância por parte dos\\nColaboradores no cumprimento das determinações contidas neste documento poderá\\nresultar na aplicação das sanções previstas no documento, incluindo penalidades\\nprevistas na Consolidação das Leis do Trabalho (CLT) ou, quando pertinente, na\\nlegislação aplicável ao caso. Tal conduta visa coibir irregularidades e\\nsituações inadequadas no ambiente de trabalho, assegurando que todos os\\ncolaboradores possam desfrutar de um ambiente seguro, saudável e adequado para\\no bom convívio. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A ação reguladora contida no\\ndocumento estende-se a todos os Colaboradores, sem distinção hierárquica, e\\ncomplementa os princípios gerais de direitos e deveres contidos na Constituição\\nFederal, na Consolidação das Leis do Trabalho e na Convenção Coletiva de\\nTrabalho aplicável. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">As relações estabelecidas entre a\\nAcademia e seus Colaboradores serão reguladas pelas normas aqui descritas, mas\\nnão se restringindo exclusivamente a elas. É sempre relevante lembrar que a\\ncomunicação e a confiança são ferramentas essenciais para a manutenção do\\nvínculo existente entre os Colaboradores e a empresa, promovendo um ambiente\\nque reflete os combinados, a verdade, integridade e confiança entre as\\npartes.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Embarque <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A admissão de um novo colaborador\\nna Academia representa mais do que o preenchimento de uma vaga: trata-se da\\nincorporação de um profissional comprometido com a nossa missão de promover\\nsaúde com excelência, responsabilidade e empatia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Cada novo integrante é inserido\\nem um ambiente fundamentado na ética, no respeito mútuo e na colaboração. Desde\\no primeiro contato, é esperado que o colaborador compreenda e se alinhe à\\ncultura organizacional da empresa, contribuindo ativamente para a manutenção de\\num clima profissional, harmonioso e voltado à qualidade no atendimento. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Com o objetivo de garantir um\\nprocesso de integração claro, eficiente e alinhado aos princípios\\ninstitucionais da Interfit, foram estabelecidas diretrizes específicas que\\norientam cada etapa da admissão. Tais procedimentos foram cuidadosamente\\nelaborados para assegurar que o novo colaborador seja acolhido de forma\\nadequada, receba as informações necessárias e inicie sua trajetória com clareza\\nquanto às responsabilidades e expectativas envolvidas em sua função. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A seguir, estão descritas as\\nnormas e orientações que podem compor o processo de admissão na Academia\\nInterfit. Mais do que exigências formais, esses passos refletem o nosso\\ncompromisso com uma gestão organizada, transparente e fundamentada na\\nvalorização das pessoas desde o início de sua jornada conosco. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">1.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit reserva-se o direito de solicitar referências\\nprofissionais dos Colaboradores durante o processo de seleção e admissão. As\\nreferências são uma ferramenta importante para avaliar a experiência,\\ncompetências técnicas e comportamentais, bem como a idoneidade dos candidatos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">2.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ao fornecer referências, o Colaborador autoriza a empresa\\na entrar em contato com antigos empregadores, colegas de trabalho ou outras\\npessoas indicadas, com o objetivo de obter informações adicionais sobre seu\\nhistórico profissional e desempenho. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">3.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Na Interfit, valoriza-se a demonstração de motivação dos\\ncandidatos e a honestidade em suas respostas. E ao ser contratado, a Interfit\\nfornecerá todas as informações necessárias para execução do trabalho, assim\\ncomo apresentará todas as regras e procedimentos internos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">4.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Informações omitidas ou destorcidas na entrevista e\\nprocesso de admissão que sejam posteriormente conhecidas pela Academia, poderão\\nser motivo de penalidade ou rescisão do contrato de trabalho. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">5.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Caso colaboradores passem a se relacionar afetivamente\\nentre si, ou com clientes, é necessário que os gestores e líderes sejam\\ninformados para medidas cabíveis conforme regimento interno. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">6.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit preza pela transparência e busca estar em\\nconformidade com as legislações que lhe são aplicáveis, e por esse e outros\\nmotivos, poderá solicitar documentações para efetiva contratação do\\nColaborador, assim como se for necessário, solicitará documentações\\ncomplementares, sempre justificando a finalidade ao Colaborador. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">7.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os colaboradores terão 04 (quatro) dias corridos para\\nentregar a documentação solicitada <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">8.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A falta de documentação adequada para a contratação\\nresultará na não efetivação da contratação, sem que isso possa ser\\ncaracterizado como expectativa frustrada, pois é uma condição imposta e não\\ncumprida pelo Candidato. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">9.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores poderão passar por processo de\\nqualificação técnica, estipulado pelo Lider de cada área, durante o período de\\nexperiência. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">10.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Durante o período de experiência, as partes avaliarão a\\nconveniência de estabelecer um vínculo definitivo. A Interfit conhecerá as\\naptidões do <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Colaborador e suas qualidades,\\nhabilidades e competências, enquanto o Colaborador verificará se o ambiente e\\nmétodos de trabalho atendem às suas expectativas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">11.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O período de experiência será de 45 (quarenta e cinco)\\ndias, prorrogáveis por mais 45 (quarenta e cinco), exceto quando a liderança\\ndeterminar formalmente a necessidade de alterar este período, sempre dentro dos\\nlimites legais. Circunstância que deverá ser formalizada. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">12.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores devem realizar todos os exames médicos\\nnecessários, conforme o caso. E na hipótese de recusa de quaisquer exames será\\nconsiderado ato de indisciplina e insubordinação. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">13.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Antes de iniciar sua jornada na Interfit, é importante que\\no Colaborador tenha plena consciência das expectativas da instituição quanto à\\nsua postura e trabalho. Um Colaborador da Interfit é aquele que: Respeita a\\ncultura e identidade da Academia, respeita seus líderes, gestores, colegas de\\ntrabalho e os clientes; vivencia o trabalho como uma missão diária; é\\ncomprometido com suas responsabilidades; cumpre os combinados do setor e função\\nem que trabalha; e <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">age conforme os valores, condutas\\ne normas da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">14.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit promove um ambiente onde expressões e\\nvocabulários ofensivos não são bem-vindos; valoriza a higiene pessoal e não\\ntolera o desrespeito entre Colaboradores, independentemente da função ou\\nhierarquia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">15.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit não tolera discriminação, assédio moral ou\\nsexual, condutas vexatórias ou qualquer comportamento que possa constranger os\\nColaboradores, os clientes, prestadores de serviços ou qualquer visitante.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">16.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Fofocas e comentários inapropriados não serão tolerados. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">17.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Como uma empresa íntegra e ética, a Academia espera que\\ntodos os Colaboradores estejam comprometidos com o trabalho, respeitando o\\nhorário de trabalho e todos os combinados estabelecidos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">18.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os horários de trabalho serão informados no momento da\\nadmissão e poderão ser alterados conforme a necessidade da empresa e a escala\\nde revezamento, este último se for o caso. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">19.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É fundamental que os Colaboradores tenham compromisso com a\\nassiduidade e pontualidade, pois essas condutas demonstram o alinhamento entre\\nos valores pessoais de cada Colaborador e os valores da Interfit <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">20.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A tolerância de atraso para os Colaboradores observará o\\ndisposto no parágrafo 1º do artigo 58 da CLT, sendo o limite máximo de atraso\\nde dez minutos diários (cinco na entrada e cinco após intervalo, por exemplo),\\nassim como eventuais peculiaridades previstas em convenção coletiva de trabalho\\nou acordo coletivo de trabalho.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">21.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Em casos de atraso superior ao estipulado, o Colaborador\\nestá ciente de que a Interfit poderá proceder com o desconto proporcional na\\nfolha de pagamento, ou demais penalidades previstas no seu contrato, neste\\nregimento interno ou na legislação. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">22.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ao tornar-se Colaborador da Interfit, é imprescindível que\\no profissional seja curioso, busque saber mais da cultura da empresa, e\\nconhecer os procedimentos e as técnicas e ferramentas utilizadas pela empresa.\\nConheça detalhadamente o presente regimento interno, assim como eventuais\\nanexos.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">23.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador deverá participar obrigatoriamente das\\natividades de integração oferecidas, incluindo apresentação da equipe, visita\\nàs instalações, treinamento inicial e orientações de segurança. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">24.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador compromete-se a manter sigilo absoluto sobre\\ninformações internas, dados de clientes, métodos de trabalho e procedimentos da\\nAcademia, desde o primeiro dia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">25.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador deverá zelar pelo patrimônio da Academia,\\nreportando danos, mau funcionamento ou riscos à liderança imediatamente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">26.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É responsabilidade do Colaborador utilizar sistemas,\\nsenhas, aplicativos internos e equipamentos digitais apenas para fins profissionais,\\nrespeitando as normas de segurança da informação. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">27.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador compromete-se a manter comunicação clara,\\nrespeitosa e objetiva com líderes, colegas e alunos, utilizando os canais\\noficiais da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">28.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador deverá apresentar-se de forma adequada, com\\nuniforme limpo e completo quando aplicável, e zelar por higiene pessoal\\ncompatível com sua função. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">29.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador deverá executar e registrar todos os\\nchecklists, rotinas diárias e operacionais determinados pelo setor,\\nespecialmente nos primeiros dias de adaptação. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">30.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Durante o período inicial, o Colaborador deve buscar\\norientação sempre que necessário, evitando improvisos que possam comprometer a\\nsegurança ou o atendimento. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">31.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador será submetido a feedback formal de\\nacompanhamento durante o período de experiência, devendo receber e aplicar\\norientações, metas e melhorias sugeridas pela liderança. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">32.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador deverá seguir todas as normas de segurança e\\nprevenção de acidentes, especialmente em ambientes com equipamentos de\\nmusculação e condicionamento físico, utilizando Equipamento de Proteção\\nIndividual (EPI) quando sua função exigir. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Travessia <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Na Interfit, compreendemos que a\\ntrajetória de cada colaborador — do ingresso à eventual saída — representa\\nmuito mais do que um vínculo contratual. Trata-se de uma jornada construída com\\npropósito, pautada no aprendizado contínuo, na colaboração e no crescimento de\\ntodos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Esse percurso é composto por\\netapas marcantes, nas quais se entrelaçam responsabilidades compartilhadas,\\noportunidades de desenvolvimento profissional e o compromisso diário com a\\nexcelência em tudo o que fazemos. Ao longo dessa jornada, espera-se de cada\\ncolaborador tenha uma postura ética, responsável e alinhada aos princípios e\\ndiretrizes estabelecidos neste Regimento Interno. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A jornada profissional na Interfit\\nreflete um relacionamento pautado no respeito, na transparência e na confiança\\nmútua. Este capítulo apresenta os fundamentos que sustentam essa experiência:\\nas condutas esperadas, os padrões de desempenho, os direitos garantidos e os\\ndeveres assumidos por cada integrante da equipe — todos em conformidade com os\\nvalores que compõem a identidade da nossa organização. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Nosso objetivo é assegurar que\\nessa vivência seja significativa, justa e inspiradora, promovendo não apenas\\nresultados consistentes, mas também um ambiente em que o ser humano seja\\ngenuinamente valorizado e em que o talento encontre espaço para se desenvolver\\ncom dignidade e reconhecimento <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Convivência <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Convivência é uma construção\\ndiária — feita de escuta, respeito e disposição para compreender o outro. Em\\nqualquer ambiente colaborativo, diferenças de opinião são naturais e até\\ndesejáveis, pois enriquecem os diálogos e favorecem a evolução coletiva. O que\\nfaz a diferença é a forma como escolhemos lidar com elas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Na Interfit, cultivamos um ambiente\\nonde o diálogo transparente, a comunicação assertiva e o respeito mútuo são\\npilares inegociáveis. Quando surgirem divergências, que sejam enfrentadas com\\nmaturidade, empatia e foco em soluções construtivas. A nossa cultura valoriza a\\ntroca saudável de ideias como ferramenta de crescimento e fortalecimento dos\\nvínculos profissionais. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Por isso, este capítulo reúne\\ndiretrizes essenciais para promover relações saudáveis, respeitosas e\\nprodutivas entre os colaboradores. Mais do que regras, são princípios que nos\\najudam a construir, diariamente, um ambiente de trabalho leve, cooperativo e\\nalinhado aos valores da Academia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">33.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Respeito acima de tudo. Trate todos com educação e\\ncordialidade, independentemente de diferenças pessoais ou profissionais. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">34.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Evite comentários ofensivos, brincadeiras de mau gosto ou\\natitudes que possam constranger colegas e clientes. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">35.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Expresse suas ideias de forma clara e objetiva, sem elevar\\no tom de voz ou interromper os outros, inclusive durante o atendimento. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">36.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ouça ativamente e demonstre empatia ao considerar\\ndiferentes pontos de vista, principalmente quando em conversa com um\\nAluno/consumidor. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">37.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Em caso de discordância, priorize o diálogo direto e\\nrespeito, buscando sempre uma solução equilibrada. No ambiente da Academia,\\nfofocas e conversinhas paralelas não serão toleradas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">38.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Caso necessário, um líder ou mediador poderá ser acionado\\npara auxiliar na resolução do conflito. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">39.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Contribua para um ambiente de colaboração, compartilhando\\nconhecimento e ajudando colegas quando possível. Lembre-se no ambiente de\\ntrabalho não há competição, e sim colaboração em prol de um único propósito. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">40.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Evite discussões desnecessárias em grupos de mensagens\\ncorporativas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">41.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Priorize a comunicação profissional e objetiva nos meios\\nformais da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">42.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Mantenha postura madura e equilibrada em todas as\\ninterações. Divergências devem ser tratadas com serenidade, sem impulsividade\\nou reatividade emocional. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">43.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Evite transformar pequenos incômodos em grandes problemas.\\nPratique a autorregulação emocional antes de responder a colegas, alunos ou\\nlíderes. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">44.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Antes de enviar uma mensagem ou fazer um comentário,\\nreflita se a informação é necessária, respeitosa e útil. Comunicação consciente\\nevita ruídos e malentendidos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">45.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ao repassar informações internas, faça-o com precisão e\\nresponsabilidade, evitando distorções ou interpretações equivocadas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">46.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Mantenha postura profissional desde a chegada à Academia\\naté o final da jornada, inclusive em áreas comuns, recepção e salas de descanso.\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">47.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Evite conversas paralelas próximas a clientes, durante o\\nexpediente ou enquanto colegas estiverem atendendo. Essas atitudes prejudicam a\\nimagem da empresa e interrompem o foco do time. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">48.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Assuntos internos da Academia não devem ser expostos a\\nclientes, terceiros ou em redes sociais. Conflitos e decisões internas\\npertencem ao ambiente de trabalho e devem ser tratados nele. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">49.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Em qualquer divergência ou situação interna, lembre-se de\\nque o bem-estar e a experiência do cliente são prioridade máxima. A convivência\\ninterna deve ser um suporte para o atendimento, nunca um obstáculo. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">50.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Caso se sinta desconfortável, injustiçado ou confuso diante\\nde alguma situação, procure a liderança. A Interfit incentiva o diálogo e\\nmantém portas abertas para conversas seguras e construtivas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Utilização de uniforme e\\nasseio pessoal <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O zelo pela imagem pessoal\\ncontribui para a credibilidade e profissionalismo tanto internamente quanto no\\natendimento aos clientes e deve ser uma conduta adotada pelos Colaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">51.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O uso de uniforme é obrigatório durante toda a jornada de\\ntrabalho do Colaborador. A empresa fornece o uniforme para todos os\\ncolaboradores, e espera que sejam utilizados de forma adequada. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">52.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A quantidade de uniforme que a empresa disponibiliza dá\\ntempo hábil para que os colaboradores não precisem reutilizar uniforme mais de\\numa vez, a ponto de utilizarem uniformes sujos ou desgastados. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">53.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores têm o dever de sinalizar quando observar\\nque um uniforme está desgastado, ficando a cargo da empresa entender se o\\ndesgaste se deu por motivos naturais | uso, ou se foi mau uso do colaborador.\\nNeste último caso, eventuais danos poderão ser descontados do colaborador. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">54.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os colaboradores deverão realizar a devolução do uniforme\\nquando do encerramento do contrato de trabalho ou quando receberem novos\\nuniformes mediante assinatura de termo de devolução. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">55.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todos os Colaboradores devem manter cuidados rigorosos com\\no asseio pessoal, garantindo uma aparência profissional. Asseio e higiene\\npessoal são questões delicadas, mas que merece atenção e cuidado de todos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">56.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Durante a jornada de trabalho é proibido o uso de boné,\\nroupas curtas, e roupas que denigram, de qualquer forma, a imagem da Academia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">57.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É terminantemente proibido utilização de uniforme de times,\\ntorcidas ou com viés político, principalmente porque o uso do uniforme é\\nobrigatório. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">58.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Durante a jornada de trabalho é obrigatório que o\\nColaborador se preocupe com asseio pessoal, afinal, lida com atendimento ao\\npúblico. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">59.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Em eventos fora da Interfit, todos os Colaboradores, embora\\nnão precisem estar uniformizados, deverão se atentar aos bons modos e costumes,\\nevitando constrangimento ou denegrir a imagem. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">60.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O uso de uniforme fora do ambiente de trabalho implica\\nresponsabilidade dos Colaboradores, uma vez que o colaborador carrega consigo a\\nimagem Interfit. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">61.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O uniforme deve ser utilizado dentro das dependências da\\nempresa e no trajeto casa-trabalho e trabalho-casa. E por esse motivo, é\\nestritamente proibido o uso do uniforme em bares ou quaisquer ambientes que\\npossam denegrir a imagem da empresa, em atividades consideradas ilícitas ou\\ninapropriadas, ou qualquer situação que possa comprometer a imagem da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">62.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Nos casos de eventos, palestras, encontros e reuniões em\\nque o uso do uniforme não seja obrigatório, os colaboradores deverão seguir um\\npadrão de vestimenta compatível com o ambiente profissional e com a imagem\\ninstitucional da Empresa. É imprescindível evitar o uso de roupas que contenham\\ndecotes, peças muito curtas, transparências, camisas de time ou qualquer outro\\nitem que possa ser considerado inadequado ou que comprometa a formalidade e o\\nrespeito ao contexto. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">63.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ao representar a empresa em eventos internos ou externos,\\nos colaboradores devem prezar por uma apresentação pessoal que transmita\\nprofissionalismo e respeito. Ainda que o uso do uniforme não seja exigido, a\\nescolha das vestimentas deve observar o equilíbrio entre o conforto e\\ndiscrição, evitando peças que possam gerar desconforto ou inadequação ao\\nambiente, como roupas excessivamente justas, curtas ou com decotes\\nexagerados.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">64.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ainda assim, em determinados eventos, a Interfit pode\\nexigir o uso do uniforme, que deverá estar em condições para uso. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Pertences Pessoais e Guarda de\\nbens <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A Interfit preza por um ambiente\\nde trabalho seguro, organizado e acolhedor. Comprometemo-nos a manter condições\\nadequadas para o bem-estar coletivo, mas é importante ressaltar que a\\nresponsabilidade pela guarda de itens pessoais é individual. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Embora adotemos medidas que\\nfavoreçam a segurança, a empresa não se responsabiliza por perdas, furtos ou\\ndanos a objetos pessoais que não estejam devidamente armazenados nos locais\\napropriados. Por isso, é fundamental que cada colaborador zele por seus\\npertences, adotando práticas preventivas como a organização do espaço de\\ntrabalho e o uso correto dos ambientes destinados à guarda de objetos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Além disso, o cuidado com os\\nambientes da Interfit — como áreas comuns, estações de trabalho e espaços de\\napoio — é responsabilidade de todos. Manter a ordem e a conservação desses\\nlocais contribui diretamente para um clima de respeito e profissionalismo,\\nrefletindo os valores que cultivamos no dia a dia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A atenção aos detalhes faz parte\\nda nossa cultura. Cuidar do que é nosso — coletivo ou individual — é também uma\\nforma de cuidar uns dos outros. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">65.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Cada Colaborador é responsável pela guarda de seus bens\\npessoais. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">66.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A empresa disponibiliza e indica um armário para guarda de\\npertences pessoais <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">67.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os armários são rotativos, devendo os colaboradores\\nretirarem seus pertences ao final de cada jornada. A Interfit não se\\nresponsabiliza por pertences deixados ou esquecidos no armário. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">68.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A perda da chave que implique danos por culpa, negligência,\\nimprudência ou imperícia do Colaborador, a empresa estará autorizada a\\ndescontar do colaborador o conserto do armário.&nbsp;\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">69.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os bens pessoais dos Colaboradores deverão ser guardados no\\nlocal indicado pela Interfit, não se responsabilizando a Academia por objetos\\ndeixados em locais inadequados e não apropriados ou simplesmente quando forem\\ndeixados no local não indicado. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">70.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Fica terminantemente proibido deixar objetos a vista do\\npúblico, fora de local indicado, em cima das bancadas de trabalho. Os motivos\\nprincipais para essa determinação são: A organização interna da empresa e o\\ncuidado com os bens dos colaboradores, que fora do local adequado podem ser\\ndanificados ou perdidos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">71.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Bens pessoais de valor elevado devem ser evitados dentro da\\nacademia. Caso seja necessário levar, a empresa deverá ser cientificada, sendo\\nque o colaborador deverá preencher o formulário de bem de valor disponível na\\nempresa, dar ciência a liderança e tomar todos os cuidados para que o bem não\\nseja perdido ou danificado dentro da empresa, assim como deverá apresentar nota\\nfiscal do objeto para que este seja mantido dentro das dependências da Academia\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">72.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador concorda que em caso de perda da chave,\\nAcademia poderá fragmentar/quebrar o cadeado para que os itens pessoais sejam\\nrecuperados, e o colaborador responsabilizado pela quebra do objeto (armário,\\nse for o caso). Para que o colaborador não seja responsabilizado pela quebra do\\nobjeto, o <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">colaborador precisará aguardar\\naté o próximo dia para, com a chave em mãos, realizar abertura do cadeado.\\nApenas nessa circunstância a regra referente a rotatividade será relevada. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">73.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Da mesma forma, se houver rescisão do contrato de trabalho\\ne o Colaborador não retirar seus bens pessoais, mantendo o armário trancado, a\\nInterfit estará autorizada a quebrar/fragmentar o cadeado, momento em que,\\nhavendo bens ou pertences, sinalizará o antigo Colaborador que o pertence\\nestará disponível com a liderança para retirada em até trinta dias corridos da\\ndata da comunicação. A ausência de manifestação ou inércia do Colaborador por\\nmais <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">de trinta dias, permitirá que a\\nempresa faça doação ou descarte os objetos encontrados dentro do armário. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">74.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Qualquer item encontrado deve ser direcionado à liderança\\nimediatamente. A liderança ao receber o objeto, enviará um comunicado aos\\nColaboradores no grupo de Whatsapp informando sobre o item encontrado.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">75.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Item perdido será colocado em um saco transparente,\\nlacrado com a data de chegada até a liderança e será guardado por 30 (trinta)\\ndias. Se o item não for reclamado dentro desse período, será doado ou\\ndescartado. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">76.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ao retirar um bem dos “achados e perdidos” (com a liderança),\\no Colaborador deverá assinar um termo de retirada do objeto. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Promoção de Saúde e Bem-estar <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Investir em iniciativas que\\nincentivem hábitos saudáveis, previnem doenças e promovem o equilíbrio entre\\nvida pessoal e profissional, e reflete o compromisso da Interfit com o\\ndesenvolvimento integral dos Colaboradores.&nbsp;\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Através de algumas condutas e\\nações de qualidade de vida, a Interfit busca criar um ambiente favorável ao\\nbem-estar físico e mental, contribuindo para a motivação, produtividade e\\nsatisfação de todos os Colaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">78.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit está comprometida em promover a saúde e o\\nbem-estar de todos os seus Colaboradores, reconhecendo a importância de um\\nambiente de trabalho saudável e equilibrado. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">79.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Academia proporciona um ambiente de trabalho acolhedor,\\nevitando sempre sobrecarga de trabalho, respeitando o limite de cada e\\nacolhendo cada colaborador com sua peculiaridade, dentro daquilo que for\\npossível e não prejudicial para a empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">80.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Mantem-se espaços de convivência agradáveis e acolhedores,\\nonde os Colaboradores são respeitados e acolhidos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">81.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit fornece condições diferenciadas para\\ncolaboradores treinarem e garante desconto para exclusivamente para cônjuge e\\nfilhos, mediante devida comprovação. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">82.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os colaboradores podem treinar sempre que desejarem e\\nquando estiverem fora do horário de trabalho. Se desejar treinar durante o\\nintervalo para alimentação, deverá estar completamente descaracterizado como\\ncolaborador. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Sobre Celulares, redes sociais\\ne veiculação de imagens&nbsp; <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O uso de celulares e o acesso a\\nredes sociais durante o expediente devem ser utilizados com cautela, sendo\\nrestrito a momentos apropriados, de modo a não comprometer o desempenho das\\nfunções e o ambiente de trabalho, podendo o colaborador utilizar quando for\\nessencial para o desenvolvimento do trabalho.&nbsp;\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A veiculação de imagens, vídeos\\nou qualquer tipo de conteúdo relacionado a Academia Interfit em redes sociais\\nou outros meios de comunicação devem ser cuidadas! E nesse sentido, alguns\\ncombinados são importantes.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">83.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A utilização de celular pessoal durante o horário de\\ntrabalho deve ser cautelosa e evitada, sendo tratada como exceção, as exceções\\n(previamente informada à liderança). Quando não observada nenhuma exceção\\nquanto a utilização dos celulares, ou quando não for exclusivamente para\\ndesenvolvimento das funções a Interfit se resguarda no direito de proibir a\\nutilização sempre que identificar ser necessário. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">84.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todos os Colaboradores estão proibidos de utilizar\\nferramentas, espaços e estrutura da Academia para promoção de serviços\\npróprios, resguardadas as exceções quando se tratar de personal interno e\\nexterno. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">85.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A veiculação de imagens relacionadas a Academia Interfit em\\nredes sociais ou outros meios de comunicação deve ser feita sempre com respeito\\nsem denegrir a imagem da empresa, assim como em todas as publicações deve ser\\nmencionado as redes sociais da Interfit.&nbsp;\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">86.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Durante eventos institucionais, os Colaboradores podem\\nutilizar seus celulares de forma responsável, evitando o uso excessivo e\\ngarantindo que a atenção esteja voltada para as atividades e clientes. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">87.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores são responsáveis por proteger e promover a\\nimagem da Interfit em suas interações online (Instagram, por exemplo), evitando\\ncomportamentos que possam prejudicar a reputação da instituição. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">88.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Durante o horário de descanso, os Colaboradores têm\\nliberdade para utilizar seus celulares e redes sociais, desde que não interfira\\nnas atividades de trabalho ou no descanso dos colegas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">89.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Em casos de extravio, perda ou depredação de equipamentos\\nde propriedade da Academia por culpa ou dolo do Colaborador, o Colaborador terá\\na responsabilidade de repor o bem, observando as características e\\nespecificidade do equipamento. Na hipótese de não reposição do bem danificado, os\\nColaboradores têm ciência de que a Academia poderá descontar do salário,\\nobservando os limites legais, conforme previsão no artigo 462 da CLT. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">90.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os dados, contatos e informações relacionadas a\\nAlunos/consumidores e fornecedores é de propriedade da Academia, e é protegido\\npor cláusula de confidencialidade, de forma que sua utilização para outros fins\\nque não seja a execução do contrato de trabalho, poderá acarretar\\nresponsabilidade por eventuais perdas e danos. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Sigilo, Confidencialidade e\\nProteção dos Dados <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O respeito ao sigilo e à\\nconfidencialidade das informações é um compromisso assumido pela Interfit.\\nTodos os Colaboradores têm a responsabilidade de proteger dados confidenciais,\\nsejam eles referentes à empresa, colegas de trabalho ou beneficiários dos\\nserviços e clientes.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A divulgação de informações\\nsensíveis ou o uso inadequado de dados internos pode causar sérios problemas\\npara a empresa e nesse trilhar, alguns combinados se fazem necessários. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">91.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores concordam que todas as informações e dados\\nque&nbsp; lhe foram fornecidos pela empresa\\ndeverão ser tratados como confidenciais, sigilosos&nbsp; e restritos, obrigando-se a respeitar\\nestritamente, sempre e a qualquer tempo, o caráter confidencial e sigiloso das\\ninformações, dados, metodologia, procedimentos e projetos da Academia, dos\\nquais venham a tomar conhecimento ou possam vir a utilizar durante a vigência\\ndo Contrato de Trabalho, os quais não poderão ser fornecidos, revelados ou\\nmencionados a terceiros, bem como não poderão ser divulgados, publicados ou\\naproveitados, por ação ou omissão, exceto se autorizado por escrito pela\\nempresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">92.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Fica desde já certo e ajustado que o disposto acima\\naplica-se também às informações dos clientes, fornecedores, parceiros e\\nColaboradores da Academia que o Colaborador eventualmente venha a ter acesso. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">93.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores serão responsabilizados pela violação do\\nsigilo ou pelo uso de informações para propósito diverso do previsto no seu\\nContrato de Trabalho, podendo acarretar a imediata rescisão deste, além da\\naplicação de outras sanções previstas em legislação específica, tais como\\nlucros cessantes, danos diretos e indiretos ou emergentes, bem como danos\\nmorais. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">94.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit, ciente da necessidade de proteger direitos\\nfundamentais de liberdade, privacidade e o livre desenvolvimento da\\npersonalidade da pessoa natural, assume o compromisso de implementar as\\ndisposições previstas na Lei Geral de Proteção de Dados, e também exigirá que\\ntodos os seus Colaboradores façam o mesmo. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">95.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A empresa realizará o tratamento de dados pessoais,\\ninclusive os dados sensíveis, nos termos da Lei nº 13.709, de 14 de agosto de\\n2018, que rege a proteção geral dos dados, por ocasião da relação de trabalho,\\ncom a finalidade de registro e eventual rescisão perante os órgãos competentes,\\nrecolhimento de tributos que decorrem da relação empregatícia, de pagamento de\\nsalário, inclusão em sistemas como E-social, e para concessão de eventuais\\nbenefícios. Assim como para execução de contrato com cliente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">96.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores se comprometem a atuar de modo a proteger\\ne garantir o tratamento/utilização adequado dos dados pessoais a que tiverem\\nacesso durante a relação contratual, bem como a cumprir as disposições\\nprevistas na Lei Geral de Proteção de Dados. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">97.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; De acordo com o que determina a LGPD, as partes obrigam-se\\na tratar os dados pessoais a que tiverem acesso unicamente para os fins e pelo\\ntempo necessário ao cumprimento das suas obrigações e à adequada execução do\\nobjeto contratual, ou ainda, com fundamento em outra base legal válida e\\nespecífica. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">98.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As senhas dos computadores e celulares de posse ou\\npropriedade da Academia não deverão ser alteradas sem a autorização expressa e\\nformalizada pelos proprietários da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">99.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As senhas dos computadores não deverão ser compartilhadas\\ncom terceiros, prestadores de serviços, alunos/consumidores, parceiros. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">100.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Em caso de perda de senha, o Colaborador deverá comunicar à\\nliderança que por sua vez providenciará assistência técnica para recuperação de\\nsenha. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">101.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É terminantemente proibido salvar informações pertencentes a\\nInterfit em computadores ou pastas individuais.&nbsp;\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Responsabilidades dos\\nColaboradores&nbsp; <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A clareza sobre as\\nresponsabilidades e deveres de cada Colaborador é essencial para o bom\\nfuncionamento da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O cumprimento das funções\\natribuídas e o respeito aos combinados estabelecidos garantem um ambiente de\\ntrabalho organizado, produtivo e em conformidade com o os valores e intenções\\nda Academia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O Regimento Interno destaca a importância\\nde que todos os Colaboradores compreendam e cumpram seus deveres e obrigações\\nobservando o seu desafio e os desafios da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O cumprimento dos combinados é um\\ndos pilares que sustentam a confiança mútua e a eficiência nas operações e\\nprocessos envolvendo a Academia.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Colaboradores que seguem suas\\natribuições e respeitam os acordos estabelecidos contribuem para um ambiente de\\ntrabalho harmonioso e produtivo, além de evitar conflitos e\\nmal-entendidos.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A intenção correta de cada\\nColaborador reflete o compromisso com a excelência. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Este regimento define as\\ndiretrizes que orientam a conduta esperada de todos os Colaboradores,\\nassegurando que cada um esteja ciente de suas responsabilidades e do impacto\\nque seu desempenho tem no sucesso coletivo. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">102.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todo Colaborador da Academia é responsável por cumprir\\nintegralmente os compromissos estabelecidos no contrato individual de trabalho,\\ndemonstrando zelo, ética, atenção e competência profissional. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">103.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É dever e obrigação de todos os Colaboradores cumprir com os\\ncombinados, solicitações e instruções provenientes de sua liderança, incluindo\\ncirculares, normas internas, direcionamentos através de Whatsapp e ferramentas\\nsimilares. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">104.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores devem seguir rigorosamente as orientações\\nrelacionadas ao uso de ferramentas de comunicação, tais como e-mail, WhatsApp,\\nentre outras, além de manter condutas apropriadas em redes sociais e demais\\nmeios de mídia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">105.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Qualquer alteração nos dados pessoais dos Colaboradores, como\\nestado civil, endereço residencial, entre outros, devem ser prontamente\\ncomunicadas à Academia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">106.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todo Colaborador tem o dever de respeitar a dignidade,\\nreputação e integridade física das pessoas com as quais interage\\nprofissionalmente em nome da Academia, independentemente de sua posição\\nhierárquica, agindo de acordo com os combinados internos da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">107.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores devem desempenhar suas atividades com\\nexcelência e segurança, tanto aquelas relacionadas às suas atribuições\\ncontratadas quanto outras eventualmente designadas pela Academia e que sejam\\nrelacionadas com sua função principal. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">108.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É dever de todos os Colaboradores agir com integridade, ética\\ne disciplina, evitando comentários negativos, condutas prejudiciais aos valores\\nda empresa, bem como abstenção de atos que possam prejudicar a Interfit, outros\\nColaboradores, prestadores de serviços, parceiros, alunos e fornecedores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">109.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É dever de todo colaborador contribuir com a organização e\\nambiência da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">110.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Nos grupos de Whatsapp destinados às atividades laborais, é\\nproibido enviar fotos, áudios, emoticons, gifs, links ou vídeos não\\nrelacionados ao trabalho e que de alguma forma possa ser considerado\\ndiscriminatório ou que denigra a imagem de qualquer cliente ou Colaborador <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">111.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Fica estritamente proibido ao Colaborador a veiculação de\\nlinguagem, imagens ou vídeos contendo conteúdo pornográfico, violento,\\npolítico, religioso ou esportivo nos grupos de comunicação da empresa, visando\\nevitar constrangimentos entre os Colaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">112.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Qualquer forma de discussão ou comportamento desrespeitoso não\\nserá tolerado nas dependências físicas ou virtuais/digitais da Academia. Conduta\\nessa destinada a manter um ambiente de trabalho harmonioso e profissional. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">113.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É estritamente proibido e considerado uma falta grave o\\nconsumo ou posse de bebidas alcoólicas ou qualquer substância que altere o\\nestado de consciência durante o expediente de trabalho e/ou nas instalações da\\nAcademia <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">114.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Comportamentos indecorosos, gestos obscenos, fofocas e\\nlinguagem inadequada não serão tolerados pela Academia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">115.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A interação entre Colaboradores, fornecedores, clientes e\\nterceiros deve ser caracterizada pela harmonia, cordialidade, respeito e\\ncompreensão mútua. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">116.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todos os Colaboradores são responsáveis por manter a ordem e a\\nlimpeza em seus postos de trabalho, seguindo rigorosamente os combinados com a\\nInterfit. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">117.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O abandono do posto de trabalho durante o expediente sem justo\\nmotivo ou autorização prévia da liderança poderá ser considerada falta grave. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">118.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Qualquer atividade de venda de produtos ou serviços pessoais\\ndentro das instalações da Interfit, seja por meio direto ou indireto, é\\nproibida.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">119.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Negócios realizados entre Colaboradores não devem atrapalhar o\\ndesenvolvimento do trabalho, assim como eventuais conflitos devem ser\\nresolvidos sem qualquer intervenção da empresa. Interações nesse sentido com\\nclientes é terminantemente proibida. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">120.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Se eventuais conflitos acontecerem decorrente do\\ndescumprimento da cláusula anterior, e afetarem a Academia, a Interfit poderá\\naplicar as sanções previstas no presente instrumento.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">121.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores devem tratar fornecedores, parceiros e\\nclientes com cortesia, atenção e profissionalismo, garantindo a qualidade das\\ninterações. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">122.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Fica terminantemente proibido aos Colaboradores solicitar\\nempréstimos financeiros a outros Colaboradores, fornecedores,\\nalunos/consumidores ou parceiros da Interfit dentro das instalações da empresa\\nou por meio de seus canais de comunicação, no horário de trabalho. Da mesma\\nforma esse tipo de interação fora do ambiente e horário de trabalho, mas que\\nimpactem na relação de trabalho, poderá ser motivo de penalidades e sanções\\nprevistas neste regimento interno. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">123.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Igualmente é terminantemente proibido que os Colaboradores\\nlevem para fora das instalações da Interfit, informações, objetos, ferramentas\\nde trabalho ou qualquer outro objeto de propriedade ou posse da Academia sem\\nprévia autorização. Quando houver necessidade de retirar algum objeto das\\ninstalações da Academia e for autorizado pela empresa, o Colaborador assinará\\num relatório com prazo para devolução. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">124.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit repudia e não tolera qualquer forma de atividade\\nilegal, incluindo trabalho infantil, trabalho forçado, desrespeito aos direitos\\nhumanos, jogos de azar, corrupção e danos ambientais e a animais, e espera que\\nseus Colaboradores e parceiros ajam de acordo com esses princípios. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">125.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As atividades dos colaboradores poderão ser alteradas de\\nacordo com as necessidades entre as partes. Ficando a cargo da empresa aceitar\\nou não eventual pedido de alteração <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Política de Reembolso <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Bons combinados não saem caro! A\\npolítica de reembolso tem como objetivo garantir que todos os Colaboradores\\nsejam devidamente reembolsados por eventuais despesas autorizadas e que estejam\\nrelacionadas às atividades profissionais.&nbsp;\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">E, portanto, algumas diretrizes e\\nprocedimentos se fazem necessários, assegurando clareza, transparência e\\norganização. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">126.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Eventuais despesas arcadas por Colaboradores e que estejam\\nrelacionados ao trabalho serão reembolsadas desde que haja autorização prévia. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">127.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O reembolso será devido quando houver autorização prévia e\\ncomprovação do gasto através de nota fiscal constando CNPJ da Interfit. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">128.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Quando não for possível obter a autorização prévia para\\nreembolso, o motivo deverá ser justificado à Liderança que avaliará o caso e,\\nentendendo ser devido, autorizará o reembolso. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">129.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os colaboradores deverão informar sobre a despesa em até 5\\ndias úteis, mediante apresentação de relatório. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Sobre a Responsabilidade por\\nDanos <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Os colaboradores da Academia têm\\no dever de zelar pelo patrimônio físico, intelectual e moral da\\norganização.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Qualquer dano, seja material ou\\ncausado por ações ou omissões que resultem em prejuízo à empresa, deverá ser\\ndevidamente apurado e, quando comprovada a responsabilidade, o colaborador\\nenvolvido poderá ser responsabilizado conforme as disposições legais e internas\\nestabelecidas abaixo. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">130.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O respeito e o cuidado com os bens da instituição são\\nprincípios essenciais para a preservação de um ambiente de trabalho seguro e\\nharmonioso. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">131.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todos os Colaboradores da empresa são responsáveis por\\nutilizar, de forma correta e diligente, os bens e recursos, zelando por sua\\nconservação.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">132.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Se no desenvolvimento do trabalho não for observado e\\ncumpridos os procedimentos adequados de cada setor/área, assim como se houver\\ncaso de negligência, erro intencional ou proposital, a punição atingirá não só\\no responsável direto pelo fato, como aqueles que tiveram ciência do fato e não\\nrealizaram a devida comunicação aos responsáveis. A negligência resultará aos\\nculpados as penalidades previstas no Regimento Interno, independentemente das\\nobrigações de ressarcimento à Academia pelos prejuízos ocasionados. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">133.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Caso um Colaborador, por ação ou omissão, venha causar danos à\\nimagem, à reputação da empresa, este poderá ser responsabilizado conforme a\\ngravidade da conduta, estando sujeito a medidas disciplinares e a ações legais,\\nquando cabíveis. Outras disposições previstas nas cláusulas “Sobre Celulares,\\nredes sociais e veiculação de imagens” devem ser observadas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">134.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Sempre que houver indícios de que um Colaborador tenha causado\\ndanos ao patrimônio ou à reputação da empresa, será realizada uma Sindicância\\nInterna para apurar os fatos. O Colaborador terá direito de ser ouvido em\\nrespeito aos princípios de ampla defesa e ao contraditório, assegurando uma\\napuração justa e transparente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">135.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Comprovada a responsabilidade do Colaborador, além de eventual\\nressarcimento por parte do Colaborador a Liderança poderá aplicar medidas\\ndisciplinares que variam desde advertência até o desligamento do colaborador\\nquando verificado danos morais para a empresa ou outros Colaboradores.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Sobre Tempo de Trabalho <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Cada minuto dedicado à\\norganização reflete não apenas o cumprimento de responsabilidades, mas também o\\ncomprometimento com os Valores compartilhados entre os Colaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O período em que o Colaborador\\nestá à disposição da empresa é um recurso valioso, sendo essencial para\\ngarantir a produtividade, a qualidade do serviço e o sucesso da empresa e\\ncolaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Entender e respeitar as regras\\nque envolvem a jornada de trabalho, pausas, eventuais horas extras e tempo à\\ndisposição é uma demonstração de responsabilidade profissional. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Assim como a correta gestão desse\\ntempo fortalece a organização, criando um ambiente de colaboração, eficiência e\\nrespeito mútuo, no qual o esforço de cada um contribui para o crescimento da\\nempresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">136.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Academia tem com seus Colaboradores uma relação de\\nconfiança, pautada em responsabilidades e com administração do próprio tempo,\\nmas também atende às determinações legais em relação às obrigatoriedades de\\njornada de seus colaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">137.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os colaboradores deverão apontar seu horário de entrada e\\nsaída, assim como saída e retorno do intervalo para almoço. O apontamento no\\ncontrole de ponto é uma atribuição importante para o Colaborador. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">138.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Conforme artigo 4º, §2º, incisos I a VIII da Consolidação das\\nLeis do Trabalho, as atividades praticadas pelo Colaborador de ordem pessoal,\\nainda que nas dependências da empresa, não são consideradas tempo à disposição\\nda Interfit, razão pela qual não poderão ser pleiteadas como horas trabalhadas.\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">139.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores não têm obrigação de responder mensagens de <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">WhatsApp ou similares, ou atender\\nligações fora do seu horário de trabalho. No mesmo sentido, ao iniciar a sua\\njornada diária as mensagens deverão ser respondidas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">140.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Cada modalidade de trabalho tem sua singela e relevante\\nimportância, assim como peculiaridades relacionadas ao horário de trabalho. E,\\nportanto, cada Colaborador deverá se atentar a sua jornada e modalidade\\ncontratual. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">141.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O descumprimento da jornada de trabalho de um Colaborador\\nprejudica diretamente os demais colaboradores e pode afetar um consumidor. Por\\nessa razão os atrasos e faltas são extremamente prejudiciais ao andamento do\\ntrabalho e devem ao máximo ser evitados. No entanto a Academia sabe que\\nfatalidades acontecem e, sendo assim, sempre que houver justificativa legal\\npara a ausência dos Colaboradores sem o desconto previsto em lei, deverá ser\\ncomunicada. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">142.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit instituiu o controle de jornada biométrico por ser\\nfidedigno a realidade dos fatos e refletir a real jornada de cada colaborador.\\nDessa forma, a Academia avaliará semanalmente o controle de jornada dos\\ncolaboradores com a intenção de validar ou identificar irregularidades. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">143.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A ausência do registro de ponto, ou seu registro equivocado\\ninduz o setor responsável à erro, razão pela qual estará passível de\\nadvertência, suspensão ou justa causa quando cabíveis. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">144.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A marcação de ponto de forma irregular sem justificativa e por\\ndesídia do colaborador será penalizada. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">145.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O Colaborador não deve faltar ao trabalho caso não haja uma\\njustificativa legal para sua ausência. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">146.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Diante de todo o prejuízo causado pelas faltas injustificadas,\\nelas podem ensejar nas penalidades previstas na legislação trabalhista, como\\nadvertências, suspensão e justa causa e até mesmo provocar descontos nos\\nsalários dos colaboradores. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">147.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; São abonadas por lei as ausências previstas no artigo 473 da\\nConsolidação das Leis do Trabalho, observadas eventuais peculiaridades\\nprevistas em norma coletiva. Mensagens de WhatsApp e similares enviadas à\\nliderança para sinalizar ausência de determinado Colaborador e que não esteja\\nacompanhada da justificativa legal não serão abonadas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">148.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit comumente concede, fornece e realiza treinamento,\\ncursos e reuniões aos seus Colaboradores. Esses encontros, quando dentro da\\njornada de trabalho contemplam tempo à disposição já acordado em contrato de\\ntrabalho. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">149.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Quando cursos, treinamentos e reuniões são fora da jornada de\\ntrabalho do colaborador a Interfit poderá convidá-lo, circunstância em que o\\nColaborador não é obrigado a participar e quando participar não será\\nconsiderado tempo à disposição, portanto, não contemplado como labor\\nextraordinário. No mesmo sentido, a empresa poderá tornar o treinamento, curso\\nou reunião obrigatórios, situação em que o colaborador deverá comparecer e as\\nhoras investidas será tempo à disposição, podendo ser pago como hora extra ou\\ncolocadas em banco de horas. Quando o treinamento for obrigatório e fora da\\njornada de trabalho e o colaborador não comparecer sem justificativa legal,\\neste poderá ser penalizado. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">150.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os atestados médicos abonam as faltas, afastando a\\npossibilidade de aplicação de penalidade ao Colaborador. O abono de falta\\njustificado por motivo de doença será concedido mediante atestado médico,\\ndevendo conter a necessidade de ausência, qualificação do colaborador e CRM do\\nmédico. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">151.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todos os atestados médicos devem ser entregues diretamente à\\nliderança em até 48 horas, presencialmente ou via e-mail/WhatsApp ou outra\\nmodalidade de comunicação eletrônica e efetiva quando o atestado contemplar\\nmais de três dias, devendo ser entregue de forma física imediatamente ao\\nretorno do Colaborador. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">152.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit se resguarda do direito de averiguar atestados\\nmédicos que estejam rasurados ou faltando os requisitos legais. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">153.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ficam os Colaboradores advertidos que a falsificação de\\natestado médico é crime e conduta passível de dispensa por justa causa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">154.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Dispensa para consultas médicas deverão ser previamente\\nsinalizadas à liderança para que este possa se organizar operacionalmente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">155.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As dispensas médicas para fins estéticos deverão ser\\nprogramadas para os períodos de férias. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">156.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Consultas e exames médicos sem urgência deverão ser realizados\\npreferencialmente fora do período de trabalho. E quando não for possível, os\\ncolaboradores deverão sinalizar imediatamente a empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">157.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Não serão aceitos atestados médicos em nome de terceiros,\\nsalvo quando autorizado pela legislação ou norma coletiva vigente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">158.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; É facultado a Interfit encaminhar o Colaborador à médico por\\nela indicado, para que este ateste eventual incapacidade laborativa temporária\\nou permanente. O Colaborador que não se submeter a este procedimento poderá\\nsofrer sanções previstas neste documento. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Sobre Diversidade, Inclusão e\\nEquidade <o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Vivemos em uma sociedade cada vez\\nmais globalizada, interconectada e diversa — e o ambiente corporativo é um\\nreflexo direto dessa realidade. Nas empresas modernas, as equipes são formadas\\npor pessoas com diferentes histórias, experiências, culturas, etnias, gêneros e\\nvisões de mundo. Essa pluralidade, quando bem compreendida e valorizada,\\ntorna-se um poderoso motor de inovação, empatia e crescimento coletivo. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Na Interfit, a diversidade se\\nmanifesta de forma natural e genuína no nosso dia a dia. Valorizamos a\\nconvivência entre diferentes, promovendo a integração, o pertencimento e o\\nreconhecimento de cada indivíduo em sua singularidade. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">159.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Na Academia acredita-se que a diversidade, a inclusão e a\\nequidade são pilares fundamentais para construção e atingimento do propósito e\\ndessa forma internalizar as diferenças. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">160.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Considera-se que a Diversidade, Inclusão e Equidade formam uma\\ntríade capaz de materializar ainda mais o exercício da função social da empresa\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">161.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Uma regra básica prevista neste capítulo pode ser definida e\\nresumida em uma só palavra: Respeito! <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">162.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Dentro da Academia Interfit não é admitido, em hipótese\\nalguma, qualquer tipo de discriminação e exclusão de Colaboradores do meio\\nsocial interno. A Interfit busca uma conduta inclusiva de todos, inclusive\\nalunos, parceiros, fornecedores, prestadores de serviços e Colaboradores.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">163.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Caso seja identificada e comprovada qualquer atitude ou\\nconduta discriminatória, a Interfit, primeiramente, dará oportunidade ao\\nColaborador “infrator” a possibilidade de reeducação no sentido de deixar de\\npraticar a conduta. No caso de recusa ou reincidência poderá resultar em\\nrescisão do contrato de trabalho. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">164.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Sempre que um Colaborador identificar a conduta de outro\\nColaborador praticante de discriminação ou bullying, deverá comunicar\\nimediatamente a liderança. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Câmeras de Segurança <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A Interfit, pautada pelos valores\\nde boa-fé, transparência e ética, comunica e informa seus colaboradores sobre a\\nadoção de sistema de câmeras com captação de imagem e áudio em suas\\ndependências. A medida tem finalidade exclusivamente preventiva e de segurança,\\nvisando proteger pessoas, instalações e o patrimônio institucional, bem como\\ncontribuir para um ambiente de trabalho tranquilo. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Reiteramos nosso compromisso com\\no respeito à dignidade, privacidade e liberdade de todos, observando a\\nlegislação aplicável, inclusive a LGPD (Lei nº 13.709/2018) e as legislação\\ntrabalhista.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">As câmeras serão instaladas\\nsomente em locais permitidos por lei, nunca em áreas de uso íntimo ou que\\npossam violar a intimidade dos(as) colaboradores(as), e não serão utilizadas\\npara monitoramento individualizado ou perseguição de qualquer pessoa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A empresa preza pelo diálogo e\\npela compreensão, mantendo-se à disposição para esclarecimentos acerca do\\nfuncionamento, finalidade, locais de instalação e prazos de guarda das\\ngravações. Este anexo descreve, de forma clara e acessível, os princípios, limites\\ne procedimentos que norteiam o uso do sistema, reforçando nossa cultura de\\nresponsabilidade, segurança e respeito no ambiente de trabalho. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A Academia informa que mantém em\\nsuas dependências sistema de câmeras de segurança com captação de imagem e\\náudio, instaladas com a exclusiva finalidade de: <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span style=\\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif;\\nmso-bidi-font-family:&quot;Segoe UI Symbol&quot;\\">➢</span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Garantir a segurança física dos colaboradores, Alunos,\\nfornecedores e visitantes; <span style=\\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif;\\nmso-bidi-font-family:&quot;Segoe UI Symbol&quot;\\">➢</span> Proteger o patrimônio da empresa; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span style=\\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif;\\nmso-bidi-font-family:&quot;Segoe UI Symbol&quot;\\">➢</span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Prevenir situações de risco, incidentes ou condutas\\nilícitas no ambiente corporativo; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span style=\\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif;\\nmso-bidi-font-family:&quot;Segoe UI Symbol&quot;\\">➢</span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Dar maior tranquilidade e confiabilidade às atividades\\ndesenvolvidas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">165.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As câmeras serão instaladas apenas em locais permitidos por\\nlei, tais como áreas comuns, entradas, saídas, setores de atendimento,\\ncorredores, áreas externas e ambientes de circulação, nunca em locais de uso\\nrestrito e privado, como banheiros, vestiários, áreas de descanso ou qualquer\\noutro ambiente que possa violar a intimidade e a privacidade dos colaboradores.\\n<o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">166.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O monitoramento não será utilizado para fiscalização individualizada\\nou direcionada a qualquer colaborador, mas sim como medida geral de segurança e\\nprevenção; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">167.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O sistema não será empregado para interferir na liberdade de\\ntrabalho, privacidade pessoal ou autonomia dos colaboradores; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">168.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As imagens e áudios captados têm caráter sigiloso e são\\nrestritos à direção da empresa e/ou setores responsáveis pela segurança, sendo\\nvedado o uso para fins diversos dos descritos neste anexo. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">169.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O acesso será restrito a pessoas autorizadas pela direção da\\nempresa, em caráter confidencial; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">170.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As informações serão armazenadas pelo período necessário à sua\\nfinalidade de segurança, podendo ser utilizadas como meio de prova em eventual\\nprocesso administrativo, judicial ou investigativo, quando cabível. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">171.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ao tomar conhecimento deste anexo, o colaborador declara estar\\nciente de que a presença das câmeras no ambiente de trabalho: <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span style=\\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif;\\nmso-bidi-font-family:&quot;Segoe UI Symbol&quot;\\">➢</span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Tem caráter preventivo e protetivo, voltado à segurança\\ncoletiva e do próprio negócio; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span style=\\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif;\\nmso-bidi-font-family:&quot;Segoe UI Symbol&quot;\\">➢</span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Não constitui violação de sua liberdade ou privacidade,\\ndesde que respeitados os limites legais aqui descritos; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><span style=\\"font-family:&quot;Segoe UI Symbol&quot;,sans-serif;\\nmso-bidi-font-family:&quot;Segoe UI Symbol&quot;\\">➢</span>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Não será utilizada como meio de perseguição,\\nconstrangimento ou fiscalização arbitrária. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Sanções e Penalidades Aplicáveis <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Diálogos profundos e\\ntransformadores que ocorrem dentro de empresas e que têm como objetivo gerar\\nvalor genuíno, tanto para os negócios quanto para as pessoas envolvidas é uma\\nconduta sempre esperada pela Interfit. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Essas conversas ultrapassam os\\naspectos superficiais das interações comuns e buscam conectar os colaboradores\\ncom o propósito maior da empresa, suas relações e impacto na sociedade e na\\nexperiência do cliente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">A comunicação será sempre o ponto\\nde partida da Interfit para solucionar conflitos internos. No entanto, sabe-se\\nque o comportamento humano pode ser inesperado e impulsivo, e, portanto, a\\nAcademia tem suas regras quanto as penalidade e sanções previstas na legislação\\ne no seu Regimento Interno. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">172.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A aplicação das penalidades previstas neste documento visa a\\nmanutenção da ordem, da eficiência e da civilidade das relações de trabalho sob\\no mais alto critério de justiça e equidade. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">173.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores que infringirem as disposições do regimento\\ninterno ou outras ordens de serviço que forem determinadas pela liderança,\\npoderão sofrer as seguintes penalidades: advertência oral, advertência escrita,\\nsuspensão e demissão por justa causa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">174.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As penalidades acima descritas poderão ser aplicadas\\nindependente de sua ordem cronológica em conformidade com a falta praticada,\\nlevando em consideração os pressupostos de: imediatidade, prova robusta da\\nconduta faltosa, proporcionalidade e razoabilidade e vedação da dupla punição. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">175.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; As penas serão aplicadas pela liderança e levarão a ciência do\\nColaborador faltoso. Na recusa de o Colaborador em assinar, duas testemunhas\\ndeverão assinar o documento. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">176.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; A Interfit se reserva no direito de instaurar sindicância\\ninterna para averiguação de conduta faltosa praticada por colaboradores. Nessa\\ncircunstância, a depender da gravidade da conduta, poderá encaminhar o\\nColaborador para sua residência, sem prejuízo do salário, até que se conclua a\\nsindicância e seja tomada uma decisão pela Academia <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">177.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Quando instaurado processo de sindicância interna para\\napuração de falta grave, o lapso entre a instauração e a tomada de decisão\\nreferente a penalidade aplicada não acarretará a perda da imediatidade,\\nconsiderando, que os fatos estavam sendo averiguados. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Desembarque <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O desembarque de colaboradores é um\\nmomento significativo na relação de trabalho, representando não apenas o\\ntérmino de um ciclo, mas também a oportunidade de garantir uma transição\\nrespeitosa e organizada.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Na Academia Interfit, busca-se\\nrealizar esse processo de rescisão de contrato com respeito e clareza,\\nassegurando que todas as etapas sejam cumpridas de maneira adequada e\\ntransparente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Este procedimento abrange uma\\nsérie de combinados que visam a devolução de materiais, assinatura de\\ndocumentos necessários e o alinhamento sobre as obrigações finais de ambas as\\npartes.&nbsp; <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">O respeito e a comunicação aberta\\nsão fundamentais durante este período, contribuindo para que a saída do\\ncolaborador ocorra de forma harmoniosa, preservando a dignidade e os vínculos\\nestabelecidos ao longo do tempo. Ao seguir estas diretrizes, garantimos não\\napenas o cumprimento das obrigações legais, mas também o fortalecimento da\\ncultura de respeito e profissionalismo que caracteriza a Interfit. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">Cada Colaborador tem seu papel de\\nextrema importância para, possuindo suas funções claras e bem definidas. No\\nentanto, algumas vezes os Colaboradores decidem se afastar do seu papel por\\nentenderem que têm propósitos e valores diferentes. E está tudo bem! Alguns\\nciclos se encerram para que outros iniciem. No entanto, o que não se admite\\ndentro da Academia são condutas infratoras e desrespeitosas. Ah, isso sim, sem\\ndúvida é motivo para desembarque por parte da empresa. Dessa forma, passe-se a\\ntratar sobre combinados para o Desembarque. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">178.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Todos os Colaboradores devem devolver os pertences da empresa\\nquando houver o encerramento do contrato de trabalho, incluindo uniforme,\\nEquipamentos de Proteção Individual (quando a função exigir) ou quaisquer\\noutros materiais/objetos de propriedade e posse da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">179.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Havendo pedido de demissão o Colaborador deverá cumprir aviso\\nprévio, sendo cientificado que o não cumprimento poderá ensejar desconto na\\nrescisão. A Academia, neste caso, pode optar por não querer o aviso prévio\\ntrabalhado e indenizar o colaborador pelo período correspondente. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">180.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O pedido de demissão ou dispensa sem justo motivo, poderá ser\\nconvertido em dispensa por justa causa se durante o cumprimento do aviso\\nprévio, o Colaborador praticar condutas que infrinjam a legislação, o presente\\ndocumento e os valores da Interfit. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">181.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Constituem justa causa para a rescisão de contrato de trabalho\\n(artigo 482, CLT) pela Empresa: ato de improbidade; incontinência de conduta ou\\nmau procedimento; negociação habitual por conta própria ou alheia sem permissão\\nda empresa e quando constituir ato de concorrência à empresa para a qual\\ntrabalha o colaborador, ou for prejudicial ao serviço; condenação criminal do\\ncolaborador, passada em julgado, caso não tenha havido suspensão na execução da\\npena; Desídia no desempenhos das respectivas funções; embriagues habitual ou em\\nserviço; violação de segredo de empresa; ato de indisciplina ou de\\ninsubordinação; abandono de emprego; ato lesivo da honra ou boa fama praticada\\nno serviço contra qualquer pessoa, ou ofensas físicas, nas mesmas condições,\\nsalvo em caso de legítima defesa, própria ou de outem; ato lesivo da honra e\\nboa fama ou ofensas físicas praticadas contra a empresa e superiores\\nhierárquicos, salvo em caso de legítima defesa, própria ou de outrem; prática\\nconstante de jogos de azar; constitui igualmente justa causa para dispensa de\\ncolaborador, a prática, devidamente comprovada em inquérito administrativo, de\\natos atentatórios a segurança nacional. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">182.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O descumprimento das normas estabelecidas neste documento\\nconstitui falta grave passível de dispensa por Justa Causa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">183.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores têm ciência das suas responsabilidades,\\ndireitos e obrigações contratuais, assim como destacado neste documento, a\\nnecessidade de cumprimento da Lei Geral de Proteção de Dados, que, sendo\\ndescumprida poderá ensejar penalidades. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">184.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O não cumprimento das obrigações decorrentes do contrato de\\ntrabalho poderá ensejar rescisão do contrato. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">185.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Ainda, serão considerados como motivos para rescisão por justo\\nmotivo: agressões físicas, moral e psicológica; usar conhecimento e capital\\nintelectual (dos métodos e processos da Academia) para negócios próprios e em\\nprejuízo da empresa; apropriação indevida de itens em benefício próprio e\\nDiscriminação de gênero, raça, idade, deficiências físicas ou\\npsíquicas/mentais. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\"><b>Disposições Gerais &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;<o:p></o:p></b></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">186.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os Colaboradores devem observar o presente documento, o\\ncontrato individual de trabalho, normas coletivas e outros comunicados e\\ninstruções da empresa. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">187.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Os casos omissos no presente documento serão resolvidos de\\nacordo com a legislação vigente, quando pertinente, ou na falta desta, pelos\\nusos e costumes e princípios gerais de equidade, analogia ou alternativas\\nadministrativas. <o:p></o:p></p>\\n\\n<p class=\\"MsoNormal\\" style=\\"text-align:justify\\">188.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; O presente documento pode ser substituído por outro sempre que\\na Interfit julgar conveniente, em consequência de alteração na legislação,\\ncultura interna, entre outras disposições, obedecendo sempre a legislação\\nvigente e dando ciência aos seus Colaboradores.<o:p></o:p></p></h3>", "descricao_resumida": "Regras de conduta e normas para colaboradores"}	771d1b4f-25b7-4f42-a2f9-919a8e5df1ab	2026-04-13 17:40:40.553801+00	2026-04-17 13:28:48.211639+00
eaf2adc5-5619-4339-bc2c-0e3a338441a3	a2222222-2222-2222-2222-222222222222::pop-processo::942530e5-042c-4db0-b70d-6d05524c9773	Script - Como vender de forma eficaz	{"titulo": "Script - Como vender de forma eficaz", "conteudo": "<h2>Recepção do Visitante</h2><ul><li>\\"Bem-vindo à Interfit! Meu nome é [nome], como posso te chamar?\\"</li><li>\\"O que te trouxe até aqui hoje?\\"</li><li>⚡ Ouvir atentamente e anotar os objetivos do visitante</li></ul><h2>Tour pela Unidade</h2><ul><li>Apresentar cada área com entusiasmo e dados relevantes</li><li>Destacar diferenciais: equipamentos, horários, modalidades</li><li>⚠️ Atenção: adaptar o tour ao perfil do visitante</li></ul><h2>Apresentação dos Planos</h2><ul><li>\\"Com base no que você me contou, o plano ideal seria...\\"</li><li>Apresentar o plano premium primeiro (ancoragem)</li><li>⚡ Ação: sempre calcular o valor diário para o visitante</li></ul><h2>Fechamento</h2><ul><li>\\"Quando você gostaria de começar?\\"</li><li>Oferecer condição especial para fechamento imediato</li><li>⚠️ Atenção: nunca pressionar — o objetivo é ajudar</li><li>Se não fechar: agendar retorno e follow-up em 24h</li></ul>", "descricao_resumida": "Roteiro padronizado para atendimento e conversão"}	1521afca-4e5c-4e9e-aa59-8e70ce2c6ce6	2026-04-13 20:34:40.33447+00	2026-04-13 20:34:40.33447+00
ad35334e-54c7-42a9-9619-c4c3f3919477	a2222222-2222-2222-2222-222222222222::pop-processo::5b576ddf-3467-43ff-85ba-902ebcd191f2	Gestão de leads	{"titulo": "Gestão de leads", "conteudo": "<h2><h2>Aqui está a estruturação do Procedimento Operacional Padrão (POP) para a gestão de leads, adaptada para a unidade IFAC BAC.\\n\\n<hr>\\n\\n<h2>POP: Gestão de Leads - Unidade IFAC BAC</h2>\\n\\n<p><strong>Objetivo:</strong> Padronizar o atendimento e a conversão de novos contatos em oportunidades reais de negócio.</p>\\n\\n<h3>1. Triagem e Qualificação</h3>\\n<ul>\\n    <li><strong>Registro imediato:</strong> Inserir o lead na planilha de controle ou CRM assim que recebido.</li>\\n    <li><strong>Verificação de origem:</strong> Identificar se o lead veio via redes sociais, tráfego pago, indicação ou presencial.</li>\\n    <li><strong>Nível de interesse:</strong> Classificar o lead como <em>Frio</em> (apenas curioso), <em>Morno</em> (busca informações) ou <em>Quente</em> (quer fechar agora).</li>\\n</ul>\\n\\n<h3>2. Primeiro Contato (Regra de Ouro)</h3>\\n<ul>\\n    <li><strong>Tempo de resposta:</strong> Realizar o primeiro contato em, no máximo, 15 minutos (horário comercial).</li>\\n    <li><strong>Abordagem:</strong> Utilizar saudação padrão mencionando o nome do lead e a unidade <strong>IFAC BAC</strong>.</li>\\n    <li><strong>Coleta de dados:</strong> Confirmar nome completo, necessidade principal e melhor horário para conversa detalhada.</li>\\n</ul>\\n\\n<h3>3. Checklist de Ações Operacionais</h3>\\n<p>Utilize esta lista para garantir que nenhum lead seja abandonado:</p>\\n<ul>\\n    <li>[ ] Lead devidamente cadastrado no sistema?</li>\\n    <li>[ ] Primeira mensagem/ligação efetuada com sucesso?</li>\\n    <li>[ ] Problema/necessidade do cliente identificado?</li>\\n    <li>[ ] Proposta de valor ou apresentação de curso enviada?</li>\\n    <li>[ ] Agendamento de visita presencial ou reunião virtual realizado?</li>\\n    <li>[ ] Data de próximo contato (follow-up) definida no calendário?</li>\\n</ul>\\n\\n<h3>4. Manutenção e Follow-up</h3>\\n<blockquote>\\n    <em>\\"Um lead só deve ser descartado após pelo menos 5 tentativas de contato em dias e horários alternados.\\"</em>\\n</blockquote>\\n<ol>\\n    <li><strong>Follow-up 1:</strong> 24h após o primeiro contato (caso não tenha respondido).</li>\\n    <li><strong>Follow-up 2:</strong> 48h após o envio da proposta.</li>\\n    <li><strong>Follow-up 3:</strong> 72h para tentativa final ou migração para fluxo de nutrição (mensagens informativas).</li>\\n</ol>\\n\\n<h3>5. Finalização do Processo</h3>\\n<ul>\\n    <li><strong>Conversão:</strong> Encaminhar para matrícula e formalização de contrato.</li>\\n    <li><strong>Perda:</strong> Sinalizar o motivo real (preço, falta de tempo, localidade) para relatórios futuros.</li>\\n</ul>\\n\\n<hr>\\n<p><strong>Responsável:</strong> Equipe Comercial / Atendimento IFAC BAC</p><br></h2></h2>", "descricao_resumida": "Processo de gestão de leads da academia."}	1521afca-4e5c-4e9e-aa59-8e70ce2c6ce6	2026-04-13 20:36:56.579931+00	2026-04-13 20:36:56.579931+00
d5355f4b-e351-4f01-abf0-1f0925dd2485	a1111111-1111-1111-1111-111111111111::pop-processo::d7438842-1015-4dc6-8e73-5e0d8433b7f9	IFAC - Fechamento da Academia	{"titulo": "IFAC - Fechamento da Academia", "conteudo": "<h2>Fechamento da Academia</h2>\\n\\n<blockquote>\\n    <strong>Objetivo:</strong> Padronizar o encerramento das atividades, garantindo a segurança patrimonial, organização do ambiente e eficiência energética (redução de custos e desperdícios).</blockquote>\\n\\n<hr>\\n\\n<h3>Passo a Passo Operacional</h3>\\n\\n<h4><ul>\\n<li>\\n<p><strong>1. Verificar e Responder Mensagens&nbsp;</strong><span style=\\"color: rgb(245, 245, 245); font-size: inherit; font-weight: inherit;\\">📲</span></p>\\n<p>&nbsp;Acesse o WhatsApp e outras plataformas de atendimento.</p>\\n<p>&nbsp;Responda todas as mensagens pendentes e organize as demandas para o dia seguinte.</p></li></ul>\\n<ul>\\n<li>\\n<p><strong>2. Conferir o Caixa das Consultoras&nbsp;</strong><span style=\\"color: rgb(245, 245, 245); font-size: inherit; font-weight: inherit;\\">💰</span></p>\\n<p>&nbsp;Verifique o fechamento do caixa das consultoras.</p>\\n<p>&nbsp;Confirme valores, registros e anote qualquer inconsistência.</p></li></ul>\\n<div><ul style=\\"--tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / .5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; border-color: rgb(46, 46, 46); color: rgb(245, 245, 245);\\"><li style=\\"--tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --tw-numeric-figure: ; --tw-numeric-spacing: ; --tw-numeric-fraction: ; --tw-ring-inset: ; --tw-ring-offset-width: 0px; --tw-ring-offset-color: #fff; --tw-ring-color: rgb(59 130 246 / .5); --tw-ring-offset-shadow: 0 0 #0000; --tw-ring-shadow: 0 0 #0000; --tw-shadow: 0 0 #0000; --tw-shadow-colored: 0 0 #0000; --tw-blur: ; --tw-brightness: ; --tw-contrast: ; --tw-grayscale: ; --tw-hue-rotate: ; --tw-invert: ; --tw-saturate: ; --tw-sepia: ; --tw-drop-shadow: ; --tw-backdrop-blur: ; --tw-backdrop-brightness: ; --tw-backdrop-contrast: ; --tw-backdrop-grayscale: ; --tw-backdrop-hue-rotate: ; --tw-backdrop-invert: ; --tw-backdrop-opacity: ; --tw-backdrop-saturate: ; --tw-backdrop-sepia: ; --tw-contain-size: ; --tw-contain-layout: ; --tw-contain-paint: ; --tw-contain-style: ; border-color: rgb(46, 46, 46);\\"><p style=\\"--tw-border-spacing-y: 0; --tw-translate-x: 0; --tw-translate-y: 0; --tw-rotate: 0; --tw-skew-x: 0; --tw-skew-y: 0; --tw-scale-x: 1; --tw-scale-y: 1; --tw-pan-x: ; --tw-pan-y: ; --tw-pinch-zoom: ; --tw-scroll-snap-strictness: proximity; --tw-gradient-from-position: ; --tw-gradient-via-position: ; --tw-gradient-to-position: ; --tw-ordinal: ; --tw-slashed-zero: ; --